   */

  async initForm() {
    const {
      id, // 已登录编辑态
      mermaid, // 编辑态
    } = this.utils.getUrlParams();
    // 初始化的DSL
    let dsl = {
      participants: [{
        _id: '1',
        type: 'actor',
        name: 'user',
        desc: ''
      }]
    };
    if (id) {
      await this.dataSourceMap['getPictureInfo'].load({
        id
      }).then(res => {
        if (res.code == 0) {
          // 已登录，且信息请求成功
          this.setState({ saveCloudDisabled: false })
          if (res.data.dsl) {
            dsl = JSON.parse(res.data.dsl);
          }
        } else {
          // 未登录或数据不存在
          antd.message.warning(code.msg);
        }
      });
    } else if (mermaid) {
      dsl = this.decompressJson(mermaid)
    }

    // 初始化myForm
    await this.utils.setFields(this, 'myForm', dsl);
    this.generateCode(this.state.myForm);
  }

  async onFormValuesChange(changedValues, allValues, extParams) {
    /**
     * 表单字段值更新时，存入 state 一份，仅用于变量绑定和数据提交
     * 通过 formRefName 扩展字段定义更新的变量名
     */
    const {
      formRefName
    } = extParams;
    await this.utils.debounce(formRefName, {
      allValues,
      formRefName
    }, async ({
      allValues,
      formRefName
    }) => {
      await this.setState(state => {
        state[formRefName] = {
          ...this.state[formRefName],
          ...allValues
        };
        return state;
      });
      await this.generateCode(this.state.myForm);
      console.log(`${formRefName} changed:`, allValues);
    });
  }
  async onTabChange(activeKey) {
    // 切换面板的回调
    console.log('onChange', activeKey);
    this.setState({
      currentPanelKey: activeKey
    });
  }
  renderMermiad() {
    return <>
      <pre class="mermaid" key={this.state.mermaidCode} dangerouslySetInnerHTML={{
        __html: this.state.mermaidCode
      }}>
      </pre>
    </>;
  }
  async generateCode(myForm) {
    // 更新url的mermaid参数
    if (!this.utils.isDesignMode()) {
      const newUrl = new URL(window.location)
      newUrl.searchParams.set('mermaid', this.compressJson(myForm))
      history.replaceState({}, '', newUrl);
    }

    // 根据时序图对象和逻辑元数据，生成mermaid代码
    let code = `sequenceDiagram
autonumber
`;
    // 生成时序图对象代码
    for (i of myForm?.participants || []) {
      if ([i.name].every(v => Boolean(v))) {
        let cobjectCode = this.constants.actionMap.object.template(i);
        code = code + `${cobjectCode}\n`;
      }
    }
    // 生成逻辑代码
    for (i of myForm?.logic || []) {
      let logicCode
      if (i.logicType == 'logic' && [i.from, i.to, i.type].every(v => Boolean(v))) {
        logicCode = this.constants.actionMap.logic.template(i);
      } else if (i.logicType == 'note' && [i.objects].every(v => Boolean(v))) {
        logicCode = this.constants.actionMap.note.template(i);
      } else if (i.logicType == 'custom' && Boolean(i.code)) {
        logicCode = this.constants.actionMap.custom.template(i);
      }
      if (logicCode) {
        code = code + `${logicCode}\n`;
      }
    }
    // 更新前记录滚动位置
    const viewDom = document.querySelector('.view-container');
    const scrollTop = viewDom.scrollTop
    // 更新
    await this.setState({
      mermaidCode: code
    });
    await mermaid.run();
    // 更新后恢复滚动位置
    viewDom.scrollTop = scrollTop
    // console.log('generate code:', code);
  }

  // 保存图形到云端
  async savePicture(event) {
    const {
      id
    } = this.utils.getUrlParams();
    if (this.utils.getAuthorization() && id) {
      // 有用户凭证
      const {
        data: pictureInfo
      } = this.state.getPictureInfo;
      this.dataSourceMap['updatePicture'].load({
        id: pictureInfo.id,
        dsl: JSON.stringify(this.state.myForm),
        code: this.state.mermaidCode,
        screen_shot: this.utils.getMermaidImageUrl()
      }).then(res => {
        if (res.code == 0) {
          antd.message.success('保存成功');
        } else {
          antd.message.error(res.msg);
        }
      });
    } else {
      // 未登录，展示注册广告
      this.setState({
        isShowRegisterNotice: true
      });
    }
  }

  // 注册广告提示
  registerNoticeRender() {
    const html = `
<div>
  <h2 style="text-align:center;">
    ${this.i18n('mermaid-ui-editor-22')}
  </h2>
  <div style="padding: 0 20px">
    <p>${this.i18n('mermaid-ui-editor-22-1')}</p>
    <p>${this.i18n('mermaid-ui-editor-22-2')}</p>
    <p>${this.i18n('mermaid-ui-editor-22-3')}</p>
  </div>
</div>
`
    return <div dangerouslySetInnerHTML={{
      __html: html
    }}></div>;
  }

  // 统一关闭弹框
  async closeDialog() {
    this.setState({
      isShowRegisterNotice: false
    });
  }

  // 用户点击了注册
  async onClickRegister(event) {
    // 保存信息至localstorage
    window.localStorage.setItem('__mermaid_ui_data', JSON.stringify({
      dsl: this.state.myForm,
      code: this.state.mermaidCode
    }));
    // 跳转注册页面
    // location.href('/lowcodeRender/mermaid-ui/page/register')
  }

  async onAddNoteClick(event) {
    // 新增备注
    const newLogic = this.state.myForm?.logic || []
    const lastLogic = newLogic.findLast((item, index) => item.logicType == 'logic')
    const lastObject = lastLogic?.to
    newLogic.push({
      logicType: 'note',
      objects: lastObject ? [lastObject] : [],
      direction: 'right',
      _id: `item-${Date.now()}-${Math.random()}`,
    })
    await this.utils.setFields(this, 'myForm', {
      logic: newLogic
    })
    this.generateCode(this.state.myForm);
  }

  async onAddCustomClick(event) {
    // 新增自定义
    const newLogic = this.state.myForm?.logic || []
    newLogic.push({
      logicType: 'custom',
      code: '',
      _id: `item-${Date.now()}-${Math.random()}`,
    })
    await this.utils.setFields(this, 'myForm', {
      logic: newLogic
    })
    this.generateCode(this.state.myForm);
  }

  async onLogicChange(value, oldIndex, newIndex, overItmes) {
    // 拖拽列表数据变化时调用
    console.log('onLogicChange', value, oldIndex, newIndex, overItmes);
    await this.utils.setFields(this, 'myForm', {
      logic: value
    })
    this.generateCode(this.state.myForm);
  }

  async onLogicTypeChange({ key }, extParams) {
    // 切换逻辑类型
    console.log('onClick', key, extParams);
    const { index, item } = extParams
    let newItem = {}
    if (item.logicType !== key) {
      if (item.logicType == 'logic' && key == 'note') {
        newItem = {
          logicType: 'note',
          objects: item.from ? [item.from] : [],
          direction: 'right',
          desc: '',
          _id: item._id,
        }
      } else if (item.logicType == 'note' && key == 'logic') {
        newItem = {
          logicType: 'logic',
          from: item.objects?.[0],
          to: item.objects?.[0],
          type: "->>",
          desc: '',
          _id: item._id,
        }
      } else if (key == 'custom') {
        newItem = {
          logicType: 'custom',
          code: '',
          _id: item._id,
        }
      } else {
        newItem = {
          logicType: key,
          _id: item._id,
        }
      }
      // 更新数据
      this.state.myForm.logic[index] = newItem
      await this.utils.setFields(this, 'myForm', {
        logic: this.state.myForm.logic
      })
      this.generateCode(this.state.myForm);
    }
  }

  async onDownloadPictureClick({ item, key, keyPath, domEvent }) {
    console.log('onClick', item, key, keyPath, domEvent);
    switch (key) {
      case 'png':
        this.utils.downloadPNG(this.i18n)
        break
      case 'svg':
        this.utils.downloadSVG(this.i18n)
        break
      case 'copy':
        this.utils.copyToClipboard(this.i18n)
        break
    }
  }

  async onCopyCodeClick(event) {
    // 复制代码
    this.utils.copyTextToClipboard(this.state.mermaidCode, this.i18n)
  }

  async shareLink(event) {
    // 分享
    const { mermaid } = this.utils.getUrlParams()
    const url = `${location.protocol}://${location.host}/lowcodeRender/mermaid-ui/mermaid-ui-editor?mermaid=${encodeURIComponent(mermaid)}`
    this.utils.copyTextToClipboard(url, this.i18n)

  }

  /**
   * 压缩 JSON 数据
   * @param {object} jsonData JSON 数据
   * @returns {string} 压缩后的数据
   */
  compressJson(jsonData) {
    const jsonString = JSON.stringify(jsonData);
    const uint8Array = new TextEncoder().encode(jsonString);
    const compressed = fflate.compressSync(uint8Array);
    const string = btoa(String.fromCharCode(...compressed));
    return string;
  }

  /**
   * 解压 JSON 数据
   * @param {string} compressedData 压缩后的数据
   * @returns {object} 解压后的 JSON 数据
   */
  decompressJson(compressedData) {
    const compressed = atob(compressedData);
    const uint8Array = new Uint8Array(compressed.length);
    for (let i = 0; i < compressed.length; i++) {
      uint8Array[i] = compressed.charCodeAt(i);
    }
    const decompressed = fflate.decompressSync(uint8Array);
    const string = new TextDecoder().decode(decompressed);
    return JSON.parse(string);
  }


