    let autonumber
    // 查找最后一个 autonumber 的索引，找不到返回-1
    const lastAutonumberIndex = logics.findLastIndex((item, index) => {
      if (item.logicType == 'custom') {
        const machAutonumber = item.code.match(/autonumber (\d+)/)
        return machAutonumber && index < that.index
      } else {
        return false
      }
    })
    // 获得具体的autonumber的数字
    if (lastAutonumberIndex > -1) {
      const machAutonumber = logics[lastAutonumberIndex].code.match(/autonumber (\d+)/)
      autonumber = parseInt(machAutonumber[1], 10)
    }
    // 统计 autonumber 和 当前logic，之间所有 logicType='logic'的数目
    const count = logics
      .filter((item, index) => {
        return index > lastAutonumberIndex && index <= that.index && item.logicType == 'logic'
      })
      .length
    // 若存在autonumber，则要在数目上增加 autonumber-1
    number = autonumber ? count + autonumber - 1 : count
    // console.log(lastAutonumberIndex, autonumber, count, number)
  } else {
    number = '●'
  }
  return number
