    }
  }
  onFieldsShowChange(event, ext) {
    // 自定义查询字段显隐
    const checked = event.target.checked;
    const {
      key
    } = ext;
    if (key === null) {
      // 全选
      this.setState(state => {
        for (let k in state.searchFieldsShow) {
          state.searchFieldsShow[k] = checked;
        }
        return state;
      });
    } else {
      this.setState(state => {
        state.searchFieldsShow[key] = checked;
        return state;
      });
    }
  }

  // 我的图形卡片列表
  async onSearch(changedValues, allValues) {
    console.log('搜索对象为：', allValues);
    await this.utils.debounce('inlineSearchForm', {
      allValues
    }, async ({
      allValues
    }) => {
      await this.setState(state => {
        state.search = {
          ...state.search,
          ...allValues
        };
        return state;
      });
      this.dataSourceMap['getPicturePageList'].load({
        ...this.state.search,
        folder_id: this.state.selectedTreeNodeKey
      });
    });
  }
  async openDialog(_, initData = {}) {
    // 判断是否超额
    const max_picture_number = this.state.checkPermisson.data.max_picture_number;
    const total = this.state.getPicturePageList.data.total;
    if (total >= max_picture_number) {
      antd.message.error(`创建已达最大额度，赞助本站解锁更多权益`);
      return;
    }
    // 打开创建、编辑弹窗
    await this.setState({
      isShowDialog: true
    });
    await this.utils.setFields(this, 'myForm', {
      ...initData
    });
  }
  async onMyFormSubmit() {
    // 手动校验
    await this.$('myForm').validateFields();
    // 获取表单数据
    if (this.state.myForm?.id) {
      console.log('更新数据', this.state.myForm);
      this.dataSourceMap['updatePicture'].load(this.state.myForm).then(res => {
        if (res.code == 0) {
          antd.message.success('更新成功');
          this.dataSourceMap['getPicturePageList'].load({
            ...this.state.search,
            folder_id: this.state.selectedTreeNodeKey
          });
          this.dataSourceMap['getFolderListAll'].load();
          this.setState({
            isShowDialog: false
          });
        } else {
          antd.message.error(res.msg);
        }
      });
    } else {
      const values = this.$('myForm').getFieldsValue();
      console.log('创建数据', values);
      this.dataSourceMap['createPicture'].load(values).then(res => {
        if (res.code == 0) {
          antd.message.success('创建成功');
          this.dataSourceMap['getPicturePageList'].load({
            ...this.state.search,
            folder_id: this.state.selectedTreeNodeKey
          });
          this.dataSourceMap['getFolderListAll'].load();
          this.setState({
            isShowDialog: false
          });
        } else {
          antd.message.error(res.msg);
        }
      });
    }
  }
  async onTableRowOperate(event, extParams) {
    // 表格行操作
    const record = extParams.item;
    switch (extParams.type) {
      case 'edit':
        console.log('编辑数据', extParams);
        this.openDialog(_, record);
        break;
      case 'design':
        window.open(`/lowcodeRender/mermaid-ui/mermaid-ui-editor?id=${record.id}`);
        break;
      case 'del':
        console.log('删除数据', extParams);
        window.antd.Modal.confirm({
          content: `确认删除？`,
          onOk: () => {
            this.dataSourceMap['deletePicture'].load({
              id: record.id
            }).then(res => {
              if (res.code == 0) {
                window.antd.message.success('删除成功');
              } else {
                window.antd.message.error(res.msg);
              }
            });
          }
        });
        break;
    }
  }
  async onChangePage(pageNo, limit) {
    console.log("onChangePage", pageNo, limit);
    await this.setState(state => {
      state.search = {
        ...state.search,
        pageNo,
        limit
      };
      return state;
    });
    this.dataSourceMap['getPicturePageList'].load({
      ...this.state.search,
      folder_id: this.state.selectedTreeNodeKey
    });
  }

  // 统一处理
  closeDialog() {
    this.setState(state => {
      state.isShowDialog = false;
      state.myForm = {};
      state.isShowFolderDialog = false;
      state.folderForm = {};
      return state;
    });
  }
  async onFormValuesChange(changedValues, allValues, extParams) {
    /**
     * 表单字段值更新时，存入 state 一份，仅用于变量绑定和数据提交
     * 通过 formRefName 扩展字段定义更新的变量名
     */
    const {
      formRefName
    } = extParams;
    await this.utils.debounce(formRefName, {
      allValues,
      formRefName
    }, async ({
      allValues,
      formRefName
    }) => {
      await this.setState(state => {
        state[formRefName] = {
          ...this.state[formRefName],
          ...allValues
        };
        return state;
      });
      console.log(`${formRefName} changed:`, allValues);
    });
  }

